import React, { useState } from 'react';
import { supabase } from './supabase';

const T = {
  bg: "#060B14", bgDeep: "#03070E", surface: "#0C1525",
  border: "#1A2E4A", cyan: "#00C8FF", magenta: "#E040FB",
  textPrimary: "#E8F0FF", textMuted: "#3D5478", textSecondary: "#7A94BF",
};

const LOGO_SRC = "data:image/png;base64,";
export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) {
      setError(error.message);
      setLoading(false);
    }
    // On success, App.js onAuthStateChange handles the redirect automatically
  };

  return (
    <div style={{ minHeight: "100vh", background: T.bg, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: "'DM Sans', sans-serif" }}>
      <div style={{ width: "100%", maxWidth: 400, padding: 20 }}>
        <div style={{ textAlign: "center", marginBottom: 40 }}>
          <img src={LOGO_SRC} alt="Stretchfield" style={{ width: 180, height: 180, objectFit: "contain", marginBottom: 8 }} />
          <div style={{ color: T.textMuted, fontSize: 22, letterSpacing: "0.22em", textTransform: "uppercase", marginTop: 4 }}>WorkRoom</div>
        </div>
        <div style={{ background: T.surface, border: `1px solid ${T.border}`, borderRadius: 4, padding: 32 }}>
          <form onSubmit={handleLogin}>
            <div style={{ marginBottom: 20 }}>
              <label style={{ display: "block", color: T.textMuted, fontSize: 10, fontWeight: 700, marginBottom: 8, textTransform: "uppercase", letterSpacing: "0.14em" }}>Email</label>
              <input type="email" value={email} onChange={e => setEmail(e.target.value)} required
                style={{ width: "100%", boxSizing: "border-box", background: T.bgDeep, border: `1px solid ${T.border}`, borderRadius: 2, padding: "11px 14px", color: T.textPrimary, fontSize: 14, outline: "none", fontFamily: "inherit" }}
              />
            </div>
            <div style={{ marginBottom: 24 }}>
              <label style={{ display: "block", color: T.textMuted, fontSize: 10, fontWeight: 700, marginBottom: 8, textTransform: "uppercase", letterSpacing: "0.14em" }}>Password</label>
              <input type="password" value={password} onChange={e => setPassword(e.target.value)} required
                style={{ width: "100%", boxSizing: "border-box", background: T.bgDeep, border: `1px solid ${T.border}`, borderRadius: 2, padding: "11px 14px", color: T.textPrimary, fontSize: 14, outline: "none", fontFamily: "inherit" }}
              />
            </div>
            {error && <div style={{ color: "#F43F5E", fontSize: 12, marginBottom: 16 }}>{error}</div>}
            <button type="submit" disabled={loading}
              style={{ width: "100%", padding: "12px", background: `linear-gradient(135deg, ${T.cyan}CC, #3B7BFF)`, color: T.bg, border: "none", borderRadius: 2, fontSize: 13, fontWeight: 700, letterSpacing: "0.12em", textTransform: "uppercase", cursor: "pointer" }}>
              {loading ? "Signing in..." : "Sign In"}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
